        let captured_changes = Arc::clone(&changes);
        let mut service = Service::<Machine>::new(
            Props {
                open: Some(true),
                close_on_escape: true,
                on_open_change: Some(callback(move |open| {
                    captured_changes
                        .lock()
                        .expect("open-change callback state should not be poisoned")
                        .push(open);
                })),
                ..test_props()
            },
            &Env::default(),
            &Messages::default(),
        );

